Trigger.script:
disableTrigger("Angel sense")
disableTrigger("Demon sense")
mmp.pdb_lastupdate = {}

if Legacy then focusTime = stopStopWatch(focusStopwatch)
if focusTime and Legacy.Settings.Curing.cureEchos then cecho(" <white>Focus<DimGray> (<gold>"..focusTime.."<DimGray>)") end Legacy.Curing.bal.focus = true resetStopWatch(focusStopwatch)
end

Legacy.Curing.Dragonform = Legacy.Curing.Dragonform or {}
Legacy.Curing.Dragonform[matches[2]:title()] = Legacy.Curing.Dragonform[matches[2]:title()] or 0
Legacy.Curing.Dragonform[matches[2]:title()] = Legacy.Curing.Dragonform[matches[2]:title()] + 1

enableTrigger("Crime Catcher")
enableTrigger("Crime Stopper")
IHateMathSoIWroteThis = {fines = 0, term = 0, oldestDate = 10000, newestDate = 0 }

local date = matches[2] local name = matches[3] local crime = matches[4] local fine = matches[5] local term = matches[6]
IHateMathSoIWroteThis.fines = tonumber(IHateMathSoIWroteThis.fines) + tonumber(fine)
if tonumber(date) == IHateMathSoIWroteThis.newestDate then IHateMathSoIWroteThis.term = tonumber(IHateMathSoIWroteThis.term) + tonumber(term) else IHateMathSoIWroteThis.term = tonumber(term) end IHateMathSoIWroteThis.newestDate = tonumber(date)

if Legacy then
local rune = multimatches[2][2]
Legacy.Runes = Legacy.Runes or {}
local r = {
  ["like an open eye"] = {
    rune = "Wunjo", effect = "Cure blind"},
  ["that looks like a stick man"] = {
    rune = "Inguz", effect = "Paralysis"},
  ["shaped like a butterfly"] = {
    rune = "Nairat", effect = "Entangle"},
  ["like a closed eye"] = {
    rune = "Fehu", effect = function()
      if not fehu or fehu == 3 then fehu = 1 return "Strip insomnia"
      elseif fehu == 1 then fehu = 2 return "Sleep"
      elseif fehu == 2 then fehu = 3 return "Strip kola" end
    end
  },
  ["resembling a bell"] = {
    rune = "Mannaz", effect = "Cure deaf"},
  ["that looks like a nail"] = {
    rune = "Sowulu", effect = "Damage"},
  ["that looks like something out of your nightmares"] = {
    rune = "Kena", effect = "Fear"},
  ["shaped like a viper"] = {
    rune = "Sleizak", effect = "Voyria"},
  ["resembling an apple core"] = {
    rune = "Loshre", effect = "Anorexia"},
  ["resembling a square box"] = {
    rune = "Pithakhan", effect = "Drain mana"},
  ["like a lightning bolt"] = {
    rune = "Uruz", effect = "Heal"},
  ["resembling a leech"] = {
    rune = "Nauthiz", effect = "Hunger"},
  ["like an upward-pointing arrow"] = {
    rune = "Tiwaz", effect = "Defence strip"}
}



echo(string.rep(" ", 60-#multimatches[2][1]))
deleteFull()
if r[rune] then
  if table.contains(Legacy.Runes.smudgelist, r[rune].rune) and r[rune].rune ~= "Fehu" then
      --nothing
    else
      table.insert(Legacy.Runes.smudgelist, r[rune].rune)
    end
  local slot = multimatches[2][3]
  cechoLink("\nSlot:<white>(<cyan>"..multimatches[2][3].."<white>) ", function() send("queue addclear free smudge totem slot "..slot) end, "Smudge the rune",true ) 
  cecho(string.format("<white>(<gold>%s: <cyan>%s<white>)",
    r[rune].rune, type(r[rune].effect) == "function" and r[rune].effect() or r[rune].effect))
else
  cecho(" <red>(<ansi_yellow>unknown!<red)")
end
end

if Legacy then
local r = {
  ["like an open eye"] = {
    rune = "Wunjo", effect = "Cure blind"},
  ["that looks like a stick man"] = {
    rune = "Inguz", effect = "Paralysis"},
  ["shaped like a butterfly"] = {
    rune = "Nairat", effect = "Entangle"},
  ["like a closed eye"] = {
    rune = "Fehu", effect = function()
      if not fehu or fehu == 3 then fehu = 1 return "Strip insomnia"
      elseif fehu == 1 then fehu = 2 return "Sleep"
      elseif fehu == 2 then fehu = 3 return "Strip kola" end
    end
  },
  ["resembling a bell"] = {
    rune = "Mannaz", effect = "Cure deaf"},
  ["that looks like a nail"] = {
    rune = "Sowulu", effect = "Damage"},
  ["that looks like something out of your nightmares"] = {
    rune = "Kena", effect = "Fear"},
  ["shaped like a viper"] = {
    rune = "Sleizak", effect = "Voyria"},
  ["resembling an apple core"] = {
    rune = "Loshre", effect = "Anorexia"},
  ["resembling a square box"] = {
    rune = "Pithakhan", effect = "Drain mana"},
  ["like a lightning bolt"] = {
    rune = "Uruz", effect = "Heal"},
  ["resembling a leech"] = {
    rune = "Nauthiz", effect = "Hunger"},
  ["like an upward-pointing arrow"] = {
    rune = "Tiwaz", effect = "Defence strip"},
  ["shaped like a mighty oak"] = {
    rune = "Jera", effect = "+1 con and str"},
  ["resembling an elk"] = {
    rune = "Algiz", effect = "10% dmg reduction"},
  ["like a lion"] = {
    rune = "Berkana", effect = "lvl1 health regen"},
  ["resembling a horse"] = {
    rune = "Raido", effect = "Return location"},
  ["like a flurry of lightning bolts"] = {
    rune = "Isaz", effect = "Throws off balance"},
  ["like a rising sun"] = {
    rune = "Dagaz", effect = "Heals affs"},
  ["shaped like a yew"] = {
    rune = "Eihwaz", effect = "Removes vibes"},
  ["resembling a volcano"] = {
    rune = "Thurisaz", effect = "Hits a person"},
  ["resembling a mountain range"] = {
    rune = "Othala", effect = "Damage over time"},
}


for i = 1, #matches, 2 do
  local rune = matches[i+1]
  local line = matches[i]

  local pos = selectString(line, 1)
  moveCursor("main", pos+#line-1, getLineNumber())
  if r[rune] then
    if table.contains(Legacy.Runes.smudgelist, r[rune].rune) then
      --nothing
    else
      table.insert(Legacy.Runes.smudgelist, r[rune].rune)
    end
      Legacy.Runes.where = "ground"
      cinsertText(string.format(" <DimGrey>(<ansi_white>%s:<cyan> %s<DimGrey>)",
      r[rune].rune, type(r[rune].effect) == "function" and r[rune].effect() or r[rune].effect)) 
  else
    cinsertText(" <royal_blue>(<ansi_yellow>unknown!<royal_blue>)")
  end
end



deselect()
resetFormat()
moveCursorEnd()
end

if Legacy then
Legacy.Runes.smudgelist = {}
end

local tat = matches[3]
Legacy.Curing.Tattoos = Legacy.Curing.Tattoos or {}

if Legacy.Curing.Tattoos[matches[2]] == nil then
  Legacy.Curing.Tattoos[matches[2]] = {}
  Legacy.Curing.Tattoos[matches[2]][matches[3]] = {charges = (tonumber(matches[4]) or "n/a")}
else
Legacy.Curing.Tattoos[matches[2]][matches[3]] = {charges = (tonumber(matches[4]) or "n/a")}
end

if Legacy.Settings.Basher.goldtrack == false then return end local str = matches[2]..", "..matches[3] local name_table = string.split(str, ", ")
Legacy.Settings.Basher.Group = Legacy.Settings.Basher.Group or {}
--Add remainder of group when following a leader for _,v in pairs(name_table) do if Legacy.Settings.Basher.Group[v:title()] == nil then Legacy.Settings.Basher.Group[v:title()] = 0 end end

deleteFull()
Legacy.Settings.Basher.frenemies = Legacy.Settings.Basher.frenemies or {}

table.insert(Legacy.Settings.Basher.frenemies, "<gold>"..matches[2].." is also attacking you!")

deleteFull() local aff = matches[2]:lower() cecho("\n<white>[<gold>Predicted<white>]: <green>"..matches[2]:upper()) Legacy.Settings.Basher.Predictions = Legacy.Settings.Basher.Predictions or {}
Legacy.Settings.Basher.Predictions[aff:lower()] = true
tempTimer(10, function() Legacy.Settings.Basher.Predictions[aff:lower()] = false end)

if matches[2] ~= target then return end local ignore = { "azurite mote", "gypsum crystal", "echinacea root", "bisemutum chip", "kola nut", "black cohosh root", "skullcap flower", "dolomite grain", "irid moss", "potash crystal", "quartz grain", "ball of myrrh gum", "antimony flake", "ginger root", }
local convert = { ['piece of kelp'] = 'kelp', ['aurum flake'] = 'aurum', ['lobelia seed'] = 'lobelia', ['argentum flake'] = 'argentum', ['prickly ash bark'] = 'ash', ['stannum flake'] = 'stannum', ['bellwort flower'] = 'bellwort', ['cuprum flake'] = 'cuprum', ['bayberry bark'] = 'bayberry', ['arsenic pellet'] = 'arsenic', ['hawthorn berry'] = 'hawthorn', ['calamine crystal'] = 'calamine', ['goldenseal root'] = 'goldenseal', ['plumbum flake'] = 'plumbum', ['bloodroot leaf'] = 'bloodroot', ['magnesium chip'] = 'magnesium', ['ginseng root'] = 'ginseng', ['ferrum flake'] = 'ferrum', ['prickly pear'] = 'pear', ['calcite mote'] = 'calcite' }
if table.contains(ignore, matches[3]) then return end Ltrack.ate(convert[matches[3]])

local tbl = matches[2]:split(' ')

for _, cmd in pairs(tbl) do
  if cmd:lower():match('truewrack') then
    local index = {}
    if tbl[(table.index_of(tbl, cmd) + 1)]:lower() == target:lower() then
      index = {2, 3}
    else
      index = {1,2}
    end
    Ltrack.alch.wrackOne, Ltrack.alch.wrackTwo = tbl[(table.index_of(tbl, cmd) + index[1])]:lower(), tbl[(table.index_of(tbl, cmd) + index[2])]:lower()
  elseif cmd:lower():match('wrack') then

    local index = {}
    if tbl[(table.index_of(tbl, cmd) + 1)]:lower() == target:lower() then
      index = {2}
    else
      index = {1}
    end
    Ltrack.alch.wrackOne, Ltrack.alch.wrackTwo = tbl[(table.index_of(tbl, cmd) + index[1])]:lower(), ''
  end
end

local humourTable = { ['choleric'] = {'nausea', 'sensitivity', 'slickness'}, ['melancholic'] = {'anorexia', 'impatience', 'stupidity'}, ['phlegmatic'] = {'asthma', 'clumsiness', 'weariness'}, ['sanguine'] = {'haemophilia', 'recklessness', 'paralysis'}, }
-- if not table.contains(humourTable[matches[2]], Ltrack.alch.wrackOne) then -- Ltrack.debug('wrackOne tracking failed: Expected a '..matches[2]..' aff and got '..Ltrack.alch.wrackOne) -- return -- end -- -- if not table.contains(humourTable[matches[3]], Ltrack.alch.wrackTwo) then -- Ltrack.debug('wrackTwo tracking failed: Expected a '..matches[3]..' aff and got '..Ltrack.alch.wrackTwo) -- return -- end
Ltrack.gainedAff(Ltrack.alch.wrackOne:lower(), Ltrack.alch.wrackTwo:lower()) Ltrack.alch.wrackOne, Ltrack.wrackTwo = ''

local humourTable = { ['choleric'] = {'nausea', 'sensitivity', 'slickness'}, ['melancholic'] = {'anorexia', 'impatience', 'stupidity'}, ['phlegmatic'] = {'asthma', 'clumsiness', 'weariness'}, ['sanguine'] = {'haemophilia', 'recklessness', 'paralysis'}, }
if not table.contains(humourTable[matches[2]], Ltrack.alch.wrackOne) and not Ltrack.alch.clumsyMiss then Ltrack.debug('wrackOne tracking failed: Expected a '..matches[2]..' aff and got '..Ltrack.alch.wrackOne) return end
if Ltrack.alch.clumsyMiss == true then Ltrack.gainedAff(Ltrack.alch.wrackTwo:lower()) else Ltrack.gainedAff(Ltrack.alch.wrackOne:lower()) end Ltrack.alch.wrackOne, Ltrack.wrackTwo = ''

if ak.ai() then return end
hitrelay = {"stupidity", "epilepsy"}
OppGainedAff(table.concat(hitrelay, " "))

if ak.ai() then return end
hitrelay = {"agoraphobia", "claustrophobia"}
OppGainedAff(table.concat(hitrelay, " "))

if ak.ai() then return end
hitrelay = {"prone", "dizziness"}
OppGainedAff(table.concat(hitrelay, " "))

if ak.ai() then return end local checks = { ["choke"] = {[1] = "weariness",[2] = "nausea"}, ["roil"] = {[1] = "weariness",[2] = "asthma"}, ["parch"] = {[1] = "weariness",[2] = "haemophilia"}, ["drench"] = {[1] = "asthma",[2] = "slickness",[3] = "anorexia"}, } if ak.fluxline and ak.fluxline == matches[1] then return end ak.fluxcheck = ak.fluxcheck or "unknown" if not table.contains(checks, ak.fluxcheck) then disableTrigger("Flux Enhance") return end --cecho("<cyan>Non-Flux: <white>"..ak.fluxcheck) if ak.fluxcheck == "drench" then
else if affstrack.score[checks[ak.fluxcheck][1]] == 100 and affstrack.score[checks[ak.fluxcheck][2]] < 100 then --cecho("<cyan>\nCheck Flux: <white>"..checks[ak.fluxcheck][2]) ak.thoughtIhad(checks[ak.fluxcheck][2]) elseif affstrack.score[checks[ak.fluxcheck][1]] < 100 and affstrack.score[checks[ak.fluxcheck][2]] == 100 then --cecho("<cyan>\nCheck Flux: <white>"..checks[ak.fluxcheck][1]) ak.thoughtIhad(checks[ak.fluxcheck][1]) else
end end disableTrigger("Flux Enhance")

ak = ak or {}
ak.twoh = ak.twoh or {}
enableTrigger("Enemy Fractures")
ak.deleteFull()

if ak.ai() then return end
ak.defs.rebounding = true
weaponattack = {}
ak.scoreup(target)
attacklimb = {}
attackweapon = {} 
weaponattack = {}
boardaffs = {}

if IsTargetted(matches[2]) then 
	if ak.ai() then return end
  echo("\n")
  echo("\n")
  cecho("<cyan> REBOUNDING UP, WATCH OUT!!!!!!!!!")
  echo("\n")
  cecho("<cyan> REBOUNDING UP, WATCH OUT!!!!!!!!!")
  echo("\n")
  cecho("<cyan> REBOUNDING UP, WATCH OUT!!!!!!!!!")
  echo("\n")
  echo("\n")
  ak.defs.rebounding = true
  ak.scoreup(matches[2])
end

if ak.ai() then
	ak.limbs.currentbreak.weapon = {}
	ak.limbs.currentbreak.limb = {}
	ak.limbs.currentbreak.attacker = {}
	ak.limbs.currentbreak.who = {}
	ak.limbs.currentbreak.augment = {}
	ak.limbs.absorbed = false
	disableTrigger("Missed Single Removal Limbs")                --DO NOT CHANGE!
  disableTrigger("Parry locate")
  disableTrigger("Monk Parry")
elseif isPrompt() then
	ak.limbs.parseBreaksPrompt()
else
	ak.limbs.parseBreaks()
end

if ak.ai() then
	ak.limbs.currentbreak.weapon = {}
	ak.limbs.currentbreak.limb = {}
	ak.limbs.currentbreak.attacker = {}
	ak.limbs.currentbreak.who = {}
	ak.limbs.currentbreak.augment = {}
	ak.limbs.absorbed = false
	disableTrigger("Missed Single Removal Limbs")                --DO NOT CHANGE!
  disableTrigger("Parry locate")
  disableTrigger("Monk Parry")
elseif isPrompt() then
	ak.limbs.parseBreaksPrompt()
else
	ak.limbs.parseBreaks()
end
affstrack.score.head = 200

ak.knownmaxhealth = ak.knownmaxhealth or {}
ak.knownmaxhealth[matches[2]] = matches[3] 
ak.scoreup(matches[2])

enableTrigger("Falcon Observe Capture")
ak.deleteFull()
falcon = falcon or {}
falcon.areawho = {}
falcon.targetin = false

Alias.script:
local room = matches[3] or mmp.currentroom room = tonumber(room) or mmp.relativeroom(mmp.currentroom, room) if not room or not mmp.roomexists(room) then mmp.echo("Sorry - which room do you want to put this character in? I don't know where you are at the moment, if you want to do the current room.") return end
local char = matches[2]
if char == "clear" then setRoomChar(room, ' ') mmp.echo("Cleared the character from "..room.." ("..getRoomName(room)..")") else setRoomChar(room, char) mmp.echo("Set the "..char:sub(1,1).." character on "..room.." ("..getRoomName(room)..")") end centerview(mmp.currentroom)

local continents = mmp.getcontinents()
if not next(continents) then mmp.echo("No continents known.") else for continent, areadata in pairs(continents) do mmp.echo(continent.." continent:")
for _, areaid in ipairs(areadata) do cecho(" "..getRoomAreaName(areaid).."\n") end end end

if (matches[2] and matches[2] == "on") or (not matches[2] and not mmp.editing) then mmp.editing = true enableAlias("mm Mapping")
mmp.regenerateAreas() mmp.highlight_unfinished_rooms()
mmp.echo("Mapping mode enabled. Happy mapping!") elseif (matches[2] and matches[2] == "off") or (not matches[2] and mmp.editing) then mmp.editing = false disableAlias("mm Mapping") mmp.echo("Mapping mode disabled.") end

mmp = mmp or {}
mmp.getPathPerf = mmp.getPathPerf or createStopWatch() startStopWatch(mmp.getPathPerf)
local from, to = tonumber(matches[2]), tonumber(matches[3])
getPath(from, to)
mmp.echon = mmp.echon or echo mmp.echon("a new getPath() from "..from.." to "..to.." took "..stopStopWatch(mmp.getPathPerf).."s. There are "..#speedWalkPath.." rooms to visit in it.") echo(" ") echoLink("[unhighlight]", [[ for room in pairs(mmp.getpathhighlights) do unHighlightRoom(room) end ]], "Click me to remove highlighting from getpath")
mmp.getpathhighlights = mmp.getpathhighlights or {}
for room in pairs(mmp.getpathhighlights) do unHighlightRoom(room) end
mmp.getpathhighlights = {}
local r,g,b = unpack(color_table.yellow) local br,bg,bb = unpack(color_table.yellow) -- add the first room to the speedWalkPath, as we'd like it highlighted as well table.insert(speedWalkPath, 1, from) for i = 1, #speedWalkPath do local room = speedWalkPath[i] highlightRoom(room, r,g,b,br,bg,bb, 1, 255, 255) mmp.getpathhighlights[room] = true end
centerview(from)

echo("Welcome to Mudlet!\n")
echo("Let's adjust a few preferences to improve the visually impaired experience:\n")

setConfig("autoClearInputLine", true)
echo("Text will now be removed from the input line after it was sent ✓\n")
setConfig("showSentText", false)
echo("Text sent to the game will not appear in the main window ✓\n")

setConfig("caretShortcut", "ctrltab")
echo("Shortcut to switch between input line and main window set to Ctrl+Tab. You can also change it to either Tab or F6 in settings.\n")

if getOS() == "windows" then
  setConfig("blankLinesBehaviour", "hide")
  echo("Blank lines will be removed from the output ✓\n")
end

if getOS() == "mac" then
  echo("\nYou're on a mac and VoiceOver will skip reading text when there's lots of it coming in. Would you like to install a third-party TTS plugin to alleviate this issue?\n")
  echo("Type 'mudlet access reader' if so.\n")
  echo("See https://wiki.mudlet.org/w/Accessibility_on_OSX if you'd like to learn more.\n")
end

echo("\nThat's all, enjoy Mudlet!\n")

--This compiles the classes for each person in your enemies list
Legacy.CT.enteam = {}
for n,c in pairs(Legacy.CT.Enemies) do Legacy.CT.enteam[c] = Legacy.CT.enteam[c] or {} Legacy.CT.enteam[c].count = Legacy.CT.enteam[c].count or 0 Legacy.CT.enteam[c].who = Legacy.CT.enteam[c].who or {}
if table.contains(Legacy.CT.enteam[c].who, n) then else if Legacy.NDB.db[n] then local city = Legacy.NDB.db[n].city table.insert(Legacy.CT.enteam[c].who, "<"..Legacy.Settings.NDB.Config[city:lower()].color..">"..n) else table.insert(Legacy.CT.enteam[c].who, n) end end
if table.contains(Legacy.CT.enteam, c) then Legacy.CT.enteam[c].count = Legacy.CT.enteam[c].count + 1 else Legacy.CT.enteam[c].count = 1 end end
cecho("\n<yellow>Enemy Composition:") cecho("\n<ansi_yellow>------------------------------") for k,v in pairs(Legacy.CT.enteam) do cecho("\n<orange>"..k.." <DimGray>[<white>"..v.count.."<DimGray>]: <white>"..table.concat(v.who, ", ")) end cecho("\n<ansi_yellow>------------------------------")

local allList = "curing priority defense " local ignoreddefs = {"ironform", "insufflate", "incandescence", "hyperfocus", "heads", "haste", "frenzied", "firefly", "extispicy", "enhancedform", "eavesdropping", "eaglelegend", "dustform", "demonfury", "deliverance", "chameleon", "brains", "blunder", "blocking", "blessingofthegods", "blackboarlegend", "battlesong", "arctar", "amamaalierlegend", "alligatorlegend", "aiming", "agithtailegend", "lifebond", "lifegiver", "lifesteal", "maticlegend", "morph", "nicatorlegend", "phased", "preachblessing", "prismatic", "promosurcoat", "scholasticism", "seasonelegend", "setweapon", "shikudoform", "shinrejoinder", "spinning", "spiritwalk", "starburst", "sympathy", "tekurastance", "tongues", "tumors", "twoartsstance", "unnamablepresence", "venomsacks", "viridian", "weakvigour", "wolflegend", "xporb"}
Defup()
send("remove armour") send("queue add free wear "..Armour()) if (table.contains(Legacy.Curing.Defs[Legacy.Curing.Defs.currentset].defences, "starburst") or table.contains(Legacy.Curing.Defs[Legacy.Curing.Defs.currentset].keepup, "starburst")) and not table.contains(Legacy.Curing.Defs.current, "starburst") then send("curing off") send("queue add free ink starburst on me") end Legacy.echo("Restored '<gold>"..Legacy.Curing.Defs.currentset.."<white>' Defense Prios.")

--Adds/Removes people whom you will not reject lust from --Tremove is just a shortened version of table.remove Legacy.Curing.Lust = Legacy.Curing.Lust or {} Legacy.Curing.Lust.whiteList = Legacy.Curing.Lust.whiteList or {}
if matches[2] == nil then send('curing rejection whitelist show') elseif matches[3] ~= nil then local person = matches[3]:title()
if Legacy.NDB.db[person] then local color = Legacy.Settings.NDB.Config[Legacy.NDB.db[person].city:lower()].color Legacy.NDB.lookup(person) if matches[2] == "add" then send('curing rejection whitelist add '..person) elseif matches[2] == "remove" then send('curing rejection whitelist remove '..person) end end end

if matches[2] == 'on' and matches[3] == nil then send('allies')
tempTimer(2, [[Legacy.echo('<green><b>Adding currently lusted allies...')]]) tempTimer(4, [[Legacy.echo('<red><i>Anyone not currently added to your whitelist will be rejected.')]]) tempTimer(5, [[Legacy.echo('<red><b>To confirm enabling Curing Rejection, please send: <gold>lustlist on agree.')]])
elseif matches[2] == 'off' then send('curing rejection off') elseif matches[3] == 'agree' then send('curing rejection on') end

Legacy.NDB.qwhom = {}
if not matches[2] then restrictSearch = nil elseif string.len(matches[2]) > 1 then restrictSearch = string.title(matches[2]) else restrictSearch = nil end
enableTrigger("Catchall Names") enableTrigger("Qwhom Display") send("config pagelength 250") send("queue add free who b", false)

Legacy.Settings.Trades.Milling.Inks = {}
Legacy.echo("<red>Cancled the Milling process.")
Legacy.Settings.Trades.Milling.status = false

Legacy.Trades.Tarot = Legacy.Trades.Tarot or {}
Legacy.Settings.Trades.Tarot = Legacy.Settings.Trades.Tarot or {}
Legacy.Settings.Trades.Tarot.Cards = Legacy.Settings.Trades.Tarot.Cards or {}
Legacy.Settings.Trades.Tarot.Cards[matches[3]] = {num = 0, total = tonumber(matches[2])}
if Legacy.Settings.Trades.Tarot.Cards[matches[3]] then
Legacy.echo("Adjusted your <gold>"..matches[3]:title().."<white> cards to <gold>"..matches[2].."<white> in your Inscribing queue.")

else
Legacy.echo("Added <gold>"..matches[2].." "..matches[3]:title().."<white> cards to your Inscribing queue.")
end

Script.script:
registerAnonymousEventHandler("mmp link externals", "mmp.addWingsImperian") mmp.imperian = mmp.imperian or {}
function mmp.addWingsImperian() local function getcmd(word) return mmp.settings.removewings and [[script:if mmp.flying then sendAll("queue eqbal wear wings","queue eqbal say ]] .. word .. [[","queue eqbal remove wings",false) else sendAll("wear wings","fly",false) end]] or [[script:if mmp.flying then sendAll("queue eqbal say ]] .. word .. [[",false) else sendAll("fly",false) end]] end
if (mmp.settings.shekinah or mmp.settings.suriel) and gmcp.Room and not table.contains(gmcp.Room.Info.details, "indoors") and not table.contains(gmcp.Room.Info.details, "considered indoors") and table.contains(mmp.imperian.wingAbleAreas, getRoomArea(mmp.currentroom)) then if mmp.settings.shekinah then -- Seraphim wings - "Say shekinah" local weight = 15 if mmp.flying then weight = 1 end mmp.tempSpecialExit(4882, getcmd("shekinah"), weight) elseif mmp.settings.suriel then -- Using Orphanim wings, SURIEL works, takes you to 3885 local weight = 15 if mmp.flying == "1" then weight = 1 end mmp.tempSpecialExit(3885, getcmd("suriel"), weight) -- clear cache so mmp.getPath accounts for the new way end end mmp.clearpathcache() end
