    if not (gmcp.Char and gmcp.Room ) then
        tempTimer(2, [[Legacy_Load()]])
      return
    end
  if io.exists(getMudletHomeDir().."/Legacy/Legacy.lua") then
    Legacy = Legacy or {}
    Legacy[gmcp.Char.Status.name] = {}
    Legacy.Rift = Legacy.Rift or {}
