function Legacy.Curing.levelsTracking() local Aff = Legacy.Curing.Affs local currentLevel = 0 --table for very quick check of the affliction you are currently seeing if it's a level based affliction local levelTypes = {["unweavingbody"] = true, ["unweavingmind"] = true, ["unweavingspirit"] = true, ["melancholic"] = true, ["choleric"] = true, ["phlegmatic"] = true, ["sanguine"] = true, ["horror"] = true, ["pyre"] = true, ["burning"] = true, ["torntendons"] = true, ["skullfracture"] = true, ["wristfracture"] = true, ["crackedribs"] = true, ["pressure"] = true, ["crescendo"] = true, }
--reset counts back to zero so if no aff found, don't need to track at that point that you needed to do a resets. Legacy.Curing.Levels = { ["unweavingbody"] = 0, ["unweavingmind"] = 0, ["unweavingspirit"] = 0, ["melancholic"] = 0, ["choleric"] = 0, ["phlegmatic"] = 0, ["sanguine"] = 0, ["horror"] = 0, ["pyre"] = 0, ["burning"] = 0, ["torntendon"] = 0, ["skullfracture"] = 0, ["wristfracture"] = 0, ["crackedrib"] = 0, ["pressure"] = 0, ["crescendo"] = 0, } --loop through the current afflictions you have, check if the aff you are looking at is on the list of level based ones for k, v in pairs(Aff) do local baseAffName = k:cut(-5) ----cut(-5) removes the bracketed number from level based affs if present: unweavingbody (3) if levelTypes[baseAffName] then currentLevel = string.gsub(k, baseAffName.." %((%d)%)", "%1") --capture the number from the aff word Legacy.Curing.Levels[baseAffName] = tonumber(currentLevel) --store it end end end
