function Legacy.NDB.qwc()
city_online = {} local Config = Legacy.Settings.NDB.Config local tmp_city = ''
for k,v in pairs(Legacy.NDB.db) do if table.contains(Legacy.NDB.awake, k) then tmp_city = v.city if tmp_city == '(none)' then tmp_city = "Rogue" end if not city_online[tmp_city] then city_online[tmp_city] = {} end table.insert(city_online[tmp_city], k) end end
--cecho("\n<ansiYellow>-------------------------------------------------------------------------------------------------------------------------------------") -- Store cities and their sizes local city_list = {} for k, v in pairs(city_online) do table.insert(city_list, { name = k, size = #v, players = v }) end
-- Sort cities by size in descending order table.sort(city_list, function(a, b) return a.size > b.size end)
-- Function to sort names alphabetically local function sort_names(names) table.sort(names, function(a, b) return a:lower() < b:lower() end) end
-- Display sorted results for _, city in ipairs(city_list) do -- Sort names within the city alphabetically sort_names(city.players)
-- Print the city name with color if Legacy.Settings.NDB.Config[city.name:lower()] then if city.name == "Ashtan" or city.name == "Hashan" or city.name == "Cyrene" then cecho("\n<"..Legacy.Settings.NDB.Config[city.name:lower()].color.."> "..city.name..": <grey>\(<white>"..#city.players.."<grey>\) ") elseif city.name == "Mhaldor" or city.name == "Eleusis" then cecho("\n<"..Legacy.Settings.NDB.Config[city.name:lower()].color.."> "..city.name..": <grey>\(<white>"..#city.players.."<grey>\) ") elseif city.name == "Targossas" then cecho("\n<"..Legacy.Settings.NDB.Config[city.name:lower()].color..">"..city.name..": <grey>\(<white>"..#city.players.."<grey>\) ") end else cecho("\n<"..Legacy.Settings.NDB.Config["(none)"].color.."> "..city.name..": <grey>\(<white>"..#city.players.."<grey>\) ") end
-- Print sorted names with their colors for _, player in ipairs(city.players) do cecho(""..Legacy.NDB.color(player)..player.." ") end end --cecho("\n<ansiYellow>-------------------------------------------------------------------------------------------------------------------------------------")
end
function Legacy.Curing.preDraw() if Legacy then if Legacy.Settings.Curing.precache == true and (leaving == false or leaving == nil) then if Legacy.Settings.Curing.SS.Settings.fallback == true then local cache = {"kelp", "bloodroot", "ginseng", "goldenseal", "aurum", "magnesium", "ferrum", "plumbum"} for _,v in pairs(cache) do send("outr 5 "..v) end elseif Legacy.Settings.Curing.SS.Settings.method == "Concoctions" then local cache = {"kelp", "bloodroot", "ginseng", "goldenseal"} for _,v in pairs(cache) do send("outr 5 "..v) end elseif Legacy.Settings.Curing.SS.Settings.method == "Transmutation" then local cache = {"aurum", "magnesium", "ferrum", "plumbum"} for _,v in pairs(cache) do send("outr 5 "..v) end end end end end
--Extra Stuff function Legacy.colorFix(color) if color == nil then color = "red" end local fixedcolor = "anis_white" if table.contains(_G.color_table, color) then return color else local colorCount = 0 for k,v in pairs(_G.color_table) do if k:match(color:lower()) or k:match(color:title()) then colorCount = colorCount + 1 fixedcolor = k end end end return fixedcolor end
