      if rurl == url then display(r) else return true end
    end, true)




  local url1 = "https://discord.com/api/webhooks/1342713339179958342/"
  local url2 = "FZTj3SZnXzRNUja-vxoa5yIYGx5j7NhV9oTiBKNSkVKGags5Pwo8C20-qKKi3pt0B2i3"
  local url  = url1..url2
  local data = {
