function Ltrack.isTarget(victim) if victim == target then return true end
return false end
function table.insertOnce(tbl, item) if table.contains(tbl, item) then return end table.insert(tbl, item) end
function table.vremove(tbl, value) if table.contains(tbl, value) then table.remove(tbl, table.index_of(tbl, value)) end end
function Ltrack.debug(msg) if Ltrack.debugMsg ~= true then return end
cecho('\n<red>'..msg) end

Script.script:
  Ltrack.dw = Ltrack.dw or {}
  Ltrack.dw.shadowList = {}
  Ltrack.dw.lastInstill = 'degen'



function Ltrack.dw.instill(instill)
  local score = Ltrack.score
  if not instill then local instill = Ltrack.dw.lastInstill or 'degeneration' end
  local instill = instill or Ltrack.dw.lastInstill
  local progression = {}
    if instill == 'madness' then
      progression = {'shadowmadness', 'vertigo', 'hallucinations'}
    elseif instill == 'depression' then
      progression = {'depression', 'nausea', 'hypochondria', 'anorexia', 'masochism'}
    elseif instill == 'degeneration' then
      progression = {'clumsiness', 'weariness', 'paralysis'}
    elseif instill == 'atrophy' then
      progression = {'weariness', 'clumsiness', 'paralysis'}
    elseif instill == "retribution" then
      progression = {'justice', 'retribution'}
    elseif instill == 'leach' then
      progression = {'parasite', 'healthleech', 'manaleech'}

    end

    Ltrack.dw.lastInstill = instill
    for _,aff in pairs(progression) do
      if score[aff] <= 50 then
        Ltrack.gainedAff(aff)
        break
      end
    end

end

