Ltrack.magi = Ltrack.magi or {} Ltrack.magi.resonance = {['earth'] = 0, ['water'] = 0, ['fire'] = 0, ['air'] = 0}
local resConvert = { ["major"] = 3, ["moderate"] = 2, ["minor"] = 1, ["none"] = 0 }
--Used GMCP to track resonance states function Ltrack.magi.resTracking() for _,v in pairs(gmcp.Char.Vitals.charstats) do if v:match("rair:") then Ltrack.magi.resonance['air'] = resConvert[string.gsub(gmcp.Char.Vitals.charstats[_], "rair: ", "")] elseif v:match("rfire:") then Ltrack.magi.resonance['fire'] = resConvert[string.gsub(gmcp.Char.Vitals.charstats[_], "rfire: ", "")] elseif v:match("rwater:") then Ltrack.magi.resonance['water'] = resConvert[string.gsub(gmcp.Char.Vitals.charstats[_], "rwater: ", "")] elseif v:match("rearth:") then Ltrack.magi.resonance['earth'] = resConvert[string.gsub(gmcp.Char.Vitals.charstats[_], "rarth: ", "")] end end end registerAnonymousEventHandler('gmcp.Char.Vitals', 'Ltrack.magi.resTracking')

