lb = lb or {}

function lb.initTarget(name)
  name = name:lower():title()

  lb[name] = lb[name] or {}
  lb[name].t = lb[name].t or {}
  lb[name].hits = lb[name].hits or {
    head = 0,
    torso = 0,
    ["left arm"] = 0,
    ["right arm"] = 0,
    ["left leg"] = 0,
    ["right leg"] = 0,
  }

  raiseEvent("limb hits updated", name, "all")
end

function lb.echo(str)
  cecho("<turquoise>[Limb]: <white>" .. str .. "\n")
end

ScriptGroup.script:
Priest = Priest or {} Priest.smite = 16.6 Priest.fragility = false Priest.limbTar = "" Priest.recite = "" Priest.chasten = "" Priest.rebuke = "" Priest.pre = "stand/stand/wield mace shield/get body/get body/put body in bag/put body in bag" Priest.route = "" Priest.illuminate = false Priest.usedWrath = false
function Prepped(limb)
local limbs = { LL = "left leg", RL = "right leg", LA = "left arm", RA = "right arm", H = "head", T = "torso", }
if Priest.fragility == true then if lb[target].hits[limbs[limb]] + (Priest.smite * 2) < 100 then return false else return true end else if lb[target].hits[limbs[limb]] + Priest.smite < 100 then return false else return true end end end
function Priest.canInquis() local aff = Ltrack.score local plen = tonumber(Legacy.Aranos.prayerlength) local conviction = tonumber(Legacy.Aranos.conviction)
if aff.guilt == 100 and aff.spiritburn >= 40 and plen >= 4 then return true end
end

Script.script:
function Sap() ret = 0 local bodyCount = {
--1% "paralysis", "asthma", "clumsiness", "healthleech", "nausea", "timeloop", "sensitivity", "depression", "parasite", "retribution", "addiction", "aeon", "darkshade", "deadening", "disloyalty", "haemophilia", "hellsight", "hypersomnia", "hypochondria", "lethargy", "scytherus", "selarnia", "slickness", "weariness", "prone", "justice", "unweavingmind", "unweavingbody",
}
local mentalCount = {
--2% "stupidity", "epilepsy", "dizziness", "confusion", "recklessness", "impatience", "paranoia", "hallucinations", "masochism", "shadowmadness", "agoraphobia", "loneliness", "claustrophobia", "hallucinations", "anorexia", "dementia", "lovers", "shyness", "vertigo", "manaleech",
}
local specialCount = {
--4%
"guilt", "tenderskin", "spiritburn", "burning" --"burning",
}
local hellTrack = {
--5% "hellsight",
}
local limbCount = {
--4% "leftleg", "rightleg", "leftarm", "rightarm",
}
local bigSpecial = {
--9% "inquisition", }
for _,v in pairs(bodyCount) do
if Ltrack.score[v] > 50 then
ret = ret + 1 end end
for _,v in pairs(mentalCount) do if Ltrack.score[v] > 50 then ret = ret + 2 end end
for _,v in pairs(limbCount) do if Ltrack.score[v] == 100 then ret = ret + 4 elseif Ltrack.score[v] == 200 then ret = ret + 5.5 end end
for _,v in pairs(specialCount) do if Ltrack.score[v] > 50 then ret = ret + 4 end end
for _,v in pairs(hellTrack) do if Ltrack.score[v] > 50 then ret = ret + 5 end end
for _,v in pairs(bigSpecial) do if Ltrack.score[v] > 50 then ret = ret + 9 end end
if Ltrack.score.inquisition == 100 then ret = math.floor(ret * 1.5) end
return ret end

