function Alchy.setWrack() -- Choleric = [Nausea, Sensitivity, Slickness] -- Melancholic = [Anorexia, Impatience, Stupidity] -- Phlegmatic = [Asthma, Clumsiness, Weariness] -- Sanguine = [Haemophilia, Recklessness, Paralysis] local humours = Ltrack.alch.humours local aff = Ltrack.score local state = Alchy.attack.state local affPrio = {"paralysis", "impatience", "asthma", "slickness", "weariness", "recklessness", "anorexia"} local aff1 = '' local aff2 = ''
local humourPools = { ["nausea"] = "choleric", ["sensitivity"] = "choleric", ["slickness"] = "choleric", ["anorexia"] = "melancholic", ["impatience"] = "melancholic", ["stupidity"] = "melancholic", ["asthma"] = "phlegmatic", ["clumsiness"] = "phlegmatic", ["weariness"] = "phlegmatic", ["haemophilia"] = "sanguine", ["recklessness"] = "sanguine", ["paralysis"] = "sanguine" }
local function humourScore(humour) local aff = table.deepcopy(Ltrack.score) local humours = { ['choleric'] = {affs = {"nausea", "sensitivity", "slickness"}, score = 0}, ['melancholic'] = {affs ={"anorexia", "impatience", "stupidity"}, score = 0}, ['phlegmatic'] = {affs ={"asthma", "clumsiness", "weariness"}, score = 0}, ['sanguine'] = {affs ={"haemophilia", "recklessness", "paralysis"}, score = 0}, }
for _,v in pairs(humours[humour].affs) do if aff[v] >= 50 then humours[humour].score = humours[humour].score + 1 end end return humours[humour].score end if mode == 'group' then affPrio = { "impatience", "stupidity", "asthma", "slickness", "anorexia", "stupidity", "recklessness", "clumsiness", "haemophilia", "nausea"} elseif state == 'mayo' then affPrio = {"impatience", "asthma", "weariness", "slickness", "anorexia", "paralysis", "recklessness", } elseif state == 'bomb' then affPrio = {"impatience", "paralysis", "sensitivity", "asthma", "slickness", "weariness", "recklessness", "anorexia"} elseif state == 'lock' then affPrio = {"impatience", "asthma", "paralysis", "clumsiness", "stupidity", "haemophilia", "slickness", "weariness", "recklessness", "anorexia"} elseif state == 'bleed' then affPrio = {"haemophilia", "paralysis", "nausea", "asthma", "slickness", "weariness", "recklessness", "anorexia"} elseif state == 'groups' then affPrio = { "impatience", "stupidity", "asthma", "slickness", "anorexia", "stupidity", "recklessness", "clumsiness", "haemophilia", "nausea"} end
for _,v in pairs(affPrio) do if aff[v] < 30 then if humours.sanguine < 2 and state ~= 'groups' and state ~= 'mayo' then aff1 = 'paralysis' elseif humours.choleric >= 6 and aff.sensitivity < 100 then aff1 = 'sensitivity' aff2 = 'paralysis' elseif aff1 == '' then aff1 = v elseif aff2 == '' then aff2 = v end end end
return {aff1, aff2, humourScore('phlegmatic')}
end

ScriptGroup.script:
Bard = Bard or {} Bard.position = "front" Bard.composition = false Bard.tempo = 'allegro' Bard.tempoHits = 2 Bard.attack = { ["refrain"] = "", ["limb"] = "", ["state"] = "" }
Bard.tempoTrack = { ['adagio'] = {['front'] = 4, ['side'] = 4, ['back'] = 3}, ['moderato'] = {['front'] = 3, ['side'] = 2, ['back'] = 2}, ['allegro'] = {['front'] = 2, ['side'] = 1, ['back'] = 1}, ['none'] = {['front'] = 5, ['side'] = 2, ['back'] = 1}, }
Bard.rapier = "rapier440120" Bard.pre = "stand/stand/get gold/put gold in pack/wield "..Bard.rapier.." shield/" Bard.Q = "freestand" Bard.canFinale = false
Bard.refrain = { ["paralysis"] = "paean", ["dizziness"] = "bhajan", ["addiction"] = "gusheh", ["asthma"] = "ode", ["slickness"] = "ghazal", ["lethargy"] = "elegy", ["sensitivity"] = "prosodion", }
function Bard.prep(limb)
local limbs = { LL = "left leg", RL = "right leg", LA = "left arm", RA = "right arm", H = "head", T = "torso", }
if lb[target].hits[limbs[limb]] + Bard.limbDamage < 100 then return false else return true end end
function Bard.positionDisplay() local currentHit = Bard.tempoTrack[Bard.tempo][Bard.position] - Bard.tempoHits local tempo = Bard.tempo local position = Bard.position
local ret = '<b><ansi_red>'
local i = 0 while i < Bard.tempoTrack[Bard.tempo].front do if Bard.position == 'front' and currentHit == i then ret = ret..'[<white>X<ansi_red>]' i = i + 1 else ret = ret..'[ ]' i = i + 1 end end
local i = 0 ret = ret..'<yellow>' while i < Bard.tempoTrack[Bard.tempo].side do if Bard.position == 'side' and currentHit == i then ret = ret..'[<white>X<yellow>]' i = i + 1 else ret = ret..'[ ]' i = i + 1 end end
local i = 0 ret = ret..'<green>' while i < Bard.tempoTrack[Bard.tempo].back do if Bard.position == 'back' and currentHit == i then ret = ret..'[<white>X<green>]' i = i + 1 else ret = ret..'[ ]' i = i + 1 end end return ret end
function Bard.canExecute() local LA = lb[target].hits["left arm"] local RA = lb[target].hits["right arm"] local LL = lb[target].hits["left leg"] local RL = lb[target].hits["right leg"] local T = lb[target].hits["torso"] local H = lb[target].hits["head"] local exeConditions = false
if Bard.tempo == 'allegro' then if Bard.position == 'front' and Bard.tempoHits <= 1 then exeConditions = true end elseif Bard.tempo == 'adagio' then if Bard.position == 'side' and Bard.tempoHits == 2 then exeConditions = true end elseif Bard.tempo == 'moderato' then if Bard.position == 'front' and Bard.tempoHits <= 1 then exeConditions = true end end
if LL == 84 and H >= 84 and T == 84 and RA == 84 and LA == 84 and exeConditions then -- Full Prep minus RL return true elseif RL == 84 and H >= 84 and T == 84 and RA == 84 and LA == 84 and exeConditions then -- Full Prep minus LL return true elseif RL == 84 and H >= 84 and T == 84 and (RA == 84 or LA == 84) and exeConditions then --Legs and an Right Arm prepped return true elseif (LL == 84 or RL == 84) and H >= 84 and (LA == 84 or RA == 84) and T == 84 and exeConditions then return true elseif H >= 84 and (RA >= 84 or LA >= 84) and (table.contains(lb.recentBreaks, 'left leg') or table.contains(recentBreaks, 'right leg')) then return true end
return false -- Default return end

Script.script:
function roundUp(number, places)
	return math.ceil(number * math.pow(10,places)) / math.pow(10,places)
end

function roundDown(number, places)
	return math.floor(number * math.pow(10,places)) / math.pow(10,places)
end

function ak.queuereset()
  if wsys then
    if wsys.bals.b and wsys.bals.e then
      ak.queue.eqbal = {}
      ak.queue.sent = {}
    end
  end
end

registerAnonymousEventHandler("got balance", "ak.queuereset")
registerAnonymousEventHandler("got equilibrium", "ak.queuereset")

ak.psion = ak.psion or {} ak.psion.secondaryTimer = ak.psion.secondaryTimer or {}
function ak.psion.KillSecondaryTick(affliction) if affliction and ak.psion.secondaryTimer[affliction] then killTimer(ak.psion.secondaryTimer[affliction]) ak.psion.secondaryTimer[affliction] = nil else if ak.psion.secondaryTimer["unweavingmind"] then killTimer(ak.psion.secondaryTimer["unweavingmind"]) ak.psion.secondaryTimer["unweavingmind"] = nil end if ak.psion.secondaryTimer["unweavingbody"] then killTimer(ak.psion.secondaryTimer["unweavingbody"]) ak.psion.secondaryTimer["unweavingbody"] = nil end if ak.psion.secondaryTimer["unweavingspirit"] then killTimer(ak.psion.secondaryTimer["unweavingspirit"]) ak.psion.secondaryTimer["unweavingspirit"] = nil end end end
function ak.psion.secondaryTick(affliction) if ak.psion.secondaryTimer[affliction] then return else if affliction == "unweavingmind" then ak.psion.secondaryTimer["unweavingmind"] = tempTimer(4,[[ if affstrack.score["unweavingmind"] > 0 then OppGainedAdditive("unweavingmind",100,500) end ak.psion.secondaryTimer["unweavingmind"] = nil ]]) elseif affliction == "unweavingspirit" then ak.psion.secondaryTimer["unweavingspirit"] = tempTimer(4,[[ if affstrack.score["unweavingspirit"] > 0 then OppGainedAdditive("unweavingspirit",100,500) end ak.psion.secondaryTimer["unweavingspirit"] = nil ]]) elseif affliction == "unweavingbody" then ak.psion.secondaryTimer["unweavingbody"] = tempTimer(4,[[ if affstrack.score["unweavingbody"] > 0 then OppGainedAdditive("unweavingbody",100,500) end ak.psion.secondaryTimer["unweavingbody"] = nil ]]) end end end

